    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ status: 'failed', error_message: msg })
  });
}

const meta = data.channel_meta;
const metrics = data.metrics;
const top20 = data.top_videos || [];
const allTitles = data.all_titles || [];

const top20Block = top20.map((v, i) => 
  `${i + 1}. "${v.title}" — ${v.views.toLocaleString()} views, ${v.likes.toLocaleString()} likes, ${v.comments.toLocaleString()} comments, ${Math.round(v.duration_seconds / 60)}min, outlier: ${v.outlier_score}x median`
).join('\n');

const allTitlesBlock = allTitles.map((t, i) => `${i + 1}. ${t}`).join('\n');

const systemPrompt = `You are an elite YouTube channel strategist with deep expertise in content analysis, audience psychology, and competitive positioning. You analyze channels with surgical precision, identifying exactly what works, what fails, and where the blue-ocean opportunities are. Be specific and data-driven. No generic advice.`;

const userPrompt = `Analyze this YouTube channel in depth.

CHANNEL INFO:
- Name: ${meta.channel_name}
- Description: ${(meta.channel_description || '').slice(0, 1500)}
- Country: ${meta.country || 'Unknown'}
- Created: ${meta.channel_created_at || 'Unknown'}
- Subscribers: ${(meta.subscriber_count || 0).toLocaleString()}
- Total views: ${(meta.total_view_count || 0).toLocaleString()}
- Video count: ${meta.video_count || 0}

METRICS:
- Avg views/video: ${(metrics.avg_views_per_video || 0).toLocaleString()}
- Median views/video: ${(metrics.median_views_per_video || 0).toLocaleString()}
