  "primary_topics": ["topic1", "topic2", ...],
  "content_style": "brief description of their style (educational/entertainment/hybrid etc)",
  "target_audience_description": "who watches this channel",
  "title_patterns": {
    "common_formulas": ["formula1", "formula2"],
