    {"topic": "topic name", "saturation": "oversaturated/moderate/underserved", "video_count_seen": 5}
  ],
  "posting_schedule": "inferred posting pattern",
  "verdict": "strong_opportunity|moderate_opportunity|weak_opportunity|avoid",
  "verdict_reasoning": "2-3 sentences explaining the verdict",
  "verdict_score": 72
}`;

// Call Claude with retry
const claudeStart = Date.now();
let claudeResult = null;
let lastErr = null;

for (let attempt = 1; attempt <= 4; attempt++) {
  try {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-opus-4-6',
        max_tokens: 4096,
        system: systemPrompt,
        messages: [{ role: 'user', content: userPrompt }]
      })
    });
    if (res.ok) {
      const body = await res.json();
      claudeResult = {
        text: body.content?.[0]?.text || '',
        input_tokens: body.usage?.input_tokens || 0,
        output_tokens: body.usage?.output_tokens || 0,
        attempts: attempt
      };
      break;
    }
    const errBody = await res.text();
    if (res.status === 429) await sleep(30000);
    lastErr = `HTTP ${res.status}: ${errBody.slice(0, 300)}`;
    if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
  } catch (e) { lastErr = e.message; }
  if (attempt < 4) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
}

const claudeDuration = Date.now() - claudeStart;

if (!claudeResult) {
  await failAnalysis(`Claude analysis failed: ${lastErr}`);
  // Log failure
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: null, topic_id: null, stage: 'channel_analyze',
        scene_number: null, action: 'claude_deep_analysis', status: 'error',
        duration_ms: claudeDuration, cost_usd: 0, retry_count: 3
      })
    });
  } catch (_) {}
  return [{ json: { ...data, failed: true, error: 'claude_analysis_failed' } }];
}

// Parse Claude response
let parsed = null;
try {
  const clean = claudeResult.text.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch {
  const m = claudeResult.text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch {} }
}

if (!parsed) {
  await failAnalysis('Claude response could not be parsed as JSON');
  return [{ json: { ...data, failed: true, error: 'claude_parse_failed' } }];
}

// Cost: Opus 4.6 $15/M input, $75/M output
const costUsd = Math.round(((claudeResult.input_tokens * 15 + claudeResult.output_tokens * 75) / 1_000_000) * 10000) / 10000;

// Log success
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null, topic_id: null, stage: 'channel_analyze',
      scene_number: null, action: 'claude_deep_analysis', status: 'success',
      duration_ms: claudeDuration, cost_usd: costUsd, retry_count: (claudeResult.attempts || 1) - 1
    })
  });
} catch (_) {}

return [{ json: {
  ...data,
  claude_analysis: parsed,
  analysis_cost_usd: costUsd,
  analysis_duration_seconds: Math.round(claudeDuration / 1000),
  input_tokens: claudeResult.input_tokens,
  output_tokens: claudeResult.output_tokens,
  failed: false
} }];

// Write all analysis results to channel_analyses, then check group completion.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const analysisId = data.analysis_id;
const analysisGroupId = data.analysis_group_id;
const meta = data.channel_meta;
const metrics = data.metrics;
const claude = data.claude_analysis;
const top20 = data.top_videos || [];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Validate verdict
const validVerdicts = ['strong_opportunity', 'moderate_opportunity', 'weak_opportunity', 'avoid'];
const verdict = validVerdicts.includes(claude.verdict) ? claude.verdict : 'moderate_opportunity';
const verdictScore = typeof claude.verdict_score === 'number'
  ? Math.max(0, Math.min(100, Math.round(claude.verdict_score)))
  : 50;

// Validate growth_trajectory
const validGrowth = ['accelerating', 'stable', 'decelerating', 'dormant'];
const growth = validGrowth.includes(metrics.growth_trajectory) ? metrics.growth_trajectory : 'stable';

const patch = {
  youtube_channel_id: data.youtube_channel_id,
  channel_name: meta.channel_name,
  channel_url: data.channel_url,
  channel_description: meta.channel_description,
  channel_avatar_url: meta.channel_avatar_url,
  channel_banner_url: meta.channel_banner_url,
  country: meta.country,
  custom_url: meta.custom_url,
  channel_created_at: meta.channel_created_at,
  subscriber_count: meta.subscriber_count,
  total_view_count: meta.total_view_count,
  video_count: meta.video_count,
  avg_views_per_video: metrics.avg_views_per_video,
  median_views_per_video: metrics.median_views_per_video,
  upload_frequency_days: metrics.upload_frequency_days,
  avg_video_duration_seconds: metrics.avg_video_duration_seconds,
  estimated_monthly_views: metrics.estimated_monthly_views,
  growth_trajectory: growth,
  primary_topics: claude.primary_topics || [],
  content_style: claude.content_style || null,
  target_audience_description: claude.target_audience_description || null,
  title_patterns: claude.title_patterns || {},
  thumbnail_patterns: claude.thumbnail_patterns || {},
  scripting_depth: claude.scripting_depth || {},
  posting_schedule: claude.posting_schedule || null,
  top_videos: top20.map(v => ({
    video_id: v.video_id,
    title: v.title,
    views: v.views,
    likes: v.likes,
    comments: v.comments,
    duration_seconds: v.duration_seconds,
    outlier_score: v.outlier_score,
    published_at: v.published_at,
    thumbnail_url: v.thumbnail_url
  })),
  strengths: claude.strengths || [],
  weaknesses: claude.weaknesses || [],
  blue_ocean_opportunities: claude.blue_ocean_opportunities || [],
  content_saturation_map: claude.content_saturation_map || [],
  verdict,
  verdict_reasoning: (claude.verdict_reasoning || '').slice(0, 2000),
  verdict_score: verdictScore,
  analyzed_at: new Date().toISOString(),
  analysis_duration_seconds: data.analysis_duration_seconds || null,
  analysis_cost_usd: data.analysis_cost_usd || 0,
  status: 'completed',
  error_message: null
};

try {
  const patchRes = await fetch(`${supabaseUrl}/rest/v1/channel_analyses?id=eq.${analysisId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!patchRes.ok) {
    const errText = await patchRes.text();
    return [{ json: { ...data, write_error: `PATCH failed: HTTP ${patchRes.status}: ${errText.slice(0, 200)}` } }];
  }
} catch (e) {
  return [{ json: { ...data, write_error: e.message } }];
}

// Check if group has >= 2 completed analyses
let groupComplete = false;
let completedCount = 0;
try {
  const groupUrl = `${supabaseUrl}/rest/v1/channel_analyses?analysis_group_id=eq.${analysisGroupId}&status=eq.completed&select=id`;
  const groupRes = await fetch(groupUrl, { method: 'GET', headers: sbHeaders });
  if (groupRes.ok) {
    const rows = await groupRes.json();
    completedCount = Array.isArray(rows) ? rows.length : 0;
    groupComplete = completedCount >= 2;
  }
} catch (_) {}

// Log completion
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null, topic_id: null, stage: 'channel_analyze',
      scene_number: null, action: 'analysis_completed', status: 'success',
      duration_ms: (data.analysis_duration_seconds || 0) * 1000,
      cost_usd: data.analysis_cost_usd || 0, retry_count: 0
    })
  });
} catch (_) {}

return [{ json: {
  success: true,
  analysis_id: analysisId,
  analysis_group_id: analysisGroupId,
  channel_name: meta.channel_name,
  verdict,
  verdict_score: verdictScore,
  group_completed_count: completedCount,
  should_trigger_compare: groupComplete,
  failed: false
} }];

// If >= 2 completed analyses in the group, trigger WF_CHANNEL_COMPARE.

const data = $input.first().json;
if (data.failed || !data.should_trigger_compare) return [{ json: data }];

const webhookBase = $env.N8N_WEBHOOK_BASE || $env.WEBHOOK_URL || 'https://n8n.srv1297445.hstgr.cloud/webhook';
const dashboardToken = $env.DASHBOARD_API_TOKEN;

try {
  const res = await fetch(`${webhookBase}/channel-compare`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${dashboardToken}`
    },
    body: JSON.stringify({
      analysis_group_id: data.analysis_group_id
    })
  });
  const status = res.status;
  return [{ json: { ...data, compare_triggered: true, compare_status: status } }];
} catch (e) {
  return [{ json: { ...data, compare_triggered: false, compare_error: e.message } }];
}
